const exams = $input.first().json;
const today = new Date();
const sevenDaysFromNow = new Date(today.getTime() + 7 * 24 * 60 * 60 * 1000);
const fourteenDaysFromNow = new Date(today.getTime() + 14 * 24 * 60 * 60 * 1000);

const closingSoon = [];
const expiredButActive = [];
const neverVerified = [];
const staleData = [];

for (const exam of exams) {
  const lastDate = new Date(exam.lastDate);
  const lastVerified = exam.lastVerifiedAt ? new Date(exam.lastVerifiedAt) : null;
  const daysSinceVerified = lastVerified ? Math.floor((today - lastVerified) / (1000 * 60 * 60 * 24)) : null;

  // Applications closing within 7 days
  if (lastDate > today && lastDate <= sevenDaysFromNow && exam.isActive) {
    closingSoon.push({ title: exam.title, lastDate: exam.lastDate, daysLeft: Math.ceil((lastDate - today) / (1000 * 60 * 60 * 24)) });
  }

  // Expired but still marked active
  if (lastDate < today && exam.isActive) {
    expiredButActive.push({ title: exam.title, lastDate: exam.lastDate, category: exam.category });
  }

  // Never verified
  if (!lastVerified) {
    neverVerified.push({ title: exam.title, category: exam.category });
  }

  // Not verified in 30+ days
  if (daysSinceVerified && daysSinceVerified > 30) {
    staleData.push({ title: exam.title, daysSinceVerified, category: exam.category });
  }
}

let report = `GovtExamPath Daily Exam Report - ${today.toLocaleDateString('en-IN')}\n\n`;

report += `CLOSING WITHIN 7 DAYS (${closingSoon.length}):\n`;
closingSoon.sort((a, b) => a.daysLeft - b.daysLeft);
for (const e of closingSoon) {
  report += `  - ${e.title} | Last Date: ${e.lastDate} | ${e.daysLeft} days left\n`;
}

report += `\nEXPIRED BUT STILL ACTIVE (${expiredButActive.length}):\n`;
for (const e of expiredButActive) {
  report += `  - ${e.title} | Expired: ${e.lastDate} | Category: ${e.category}\n`;
}

report += `\nNEVER VERIFIED (${neverVerified.length}):\n`;
for (const e of neverVerified.slice(0, 20)) {
  report += `  - ${e.title} | ${e.category}\n`;
}
if (neverVerified.length > 20) report += `  ... and ${neverVerified.length - 20} more\n`;

report += `\nSTALE DATA (30+ days since verification) (${staleData.length}):\n`;
for (const e of staleData.slice(0, 20)) {
  report += `  - ${e.title} | ${e.daysSinceVerified} days ago | ${e.category}\n`;
}

report += `\n---\nTotal exams: ${exams.length}`;
report += `\nActive exams: ${exams.filter(e => e.isActive).length}`;
report += `\nNeeds attention: ${expiredButActive.length + staleData.length}`;

return [{
  json: {
    report,
    closingSoonCount: closingSoon.length,
    expiredActiveCount: expiredButActive.length,
    staleCount: staleData.length,
    totalExams: exams.length,
    expiredButActive
  }
}];
